102	export interface OpenAIProviderSettings {
103	  /**
104	   * Base URL for the OpenAI API calls.
105	   */
106	  baseURL?: string;
107	
108	  /**
109	   * API key for authenticating requests.
110	   */
111	  apiKey?: string;
112	
113	  /**
114	   * OpenAI Organization.
115	   */
116	  organization?: string;
117	
118	  /**
119	   * OpenAI project.
120	   */
121	  project?: string;
122	
123	  /**
124	   * Custom headers to include in the requests.
125	   */
126	  headers?: Record<string, string>;
127	
128	  /**
129	   * Provider name. Overrides the `openai` default name for 3rd party providers.
130	   */
131	  name?: string;
132	
133	  /**
134	   * Custom fetch implementation. You can use it as a middleware to intercept requests,
135	   * or to provide a custom fetch implementation for e.g. testing.
136	   */
137	  fetch?: FetchFunction;
