3	export function convertMoonshotAIChatUsage(
4	  usage:
5	    | {
6	        prompt_tokens?: number | null;
7	        completion_tokens?: number | null;
8	        cached_tokens?: number | null;
9	        prompt_tokens_details?: {
10	          cached_tokens?: number | null;
11	        } | null;
12	        completion_tokens_details?: {
13	          reasoning_tokens?: number | null;
14	        } | null;
15	      }
16	    | undefined
17	    | null,
18	): LanguageModelV3Usage {
19	  if (usage == null) {
20	    return {
21	      inputTokens: {
22	        total: undefined,
23	        noCache: undefined,
24	        cacheRead: undefined,
25	        cacheWrite: undefined,
26	      },
27	      outputTokens: {
28	        total: undefined,
29	        text: undefined,
30	        reasoning: undefined,
31	      },
32	      raw: undefined,
33	    };
34	  }
35	
36	  const promptTokens = usage.prompt_tokens ?? 0;
37	  const completionTokens = usage.completion_tokens ?? 0;
38	
39	  const cacheReadTokens =
40	    usage.cached_tokens ?? usage.prompt_tokens_details?.cached_tokens ?? 0;
41	
42	  const reasoningTokens =
43	    usage.completion_tokens_details?.reasoning_tokens ?? 0;
44	
45	  return {
46	    inputTokens: {
47	      total: promptTokens,
48	      noCache: promptTokens - cacheReadTokens,
49	      cacheRead: cacheReadTokens,
50	      cacheWrite: undefined,
51	    },
52	    outputTokens: {
53	      total: completionTokens,
54	      text: completionTokens - reasoningTokens,
55	      reasoning: reasoningTokens,
56	    },
57	    raw: usage,
58	  };
59	}
