import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  parseProviderOptions,
  zodSchema,
  lazySchema,
  InferSchema,
} from '@ai-sdk/provider-utils';
import { PixelArtImageSettings } from './pixelart-image-settings';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    // Parse and validate provider-specific options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    // Merge constructor settings with per-call provider options
    const effectiveSize = pixelartOptions?.size ?? this.settings.size ?? size ?? undefined;
    const effectiveStyle = pixelartOptions?.style ?? this.settings.style ?? undefined;
    const effectivePixelDensity = pixelartOptions?.pixelDensity ?? this.settings.pixelDensity ?? undefined;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n: n ?? 1,
        ...(effectiveSize != null ? { size: effectiveSize } : {}),
        ...(effectiveStyle != null ? { style: effectiveStyle } : {}),
        ...(effectivePixelDensity != null ? { pixel_density: effectivePixelDensity } : {}),
        ...(seed != null ? { seed } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: error => error.error?.message ?? 'Unknown PixelArt API error',
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
    });

    // The API returns base64-encoded image data
    const images = response.data.map(item => item.b64_json);

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

/**
 * Schema for PixelArt API image generation response.
 */
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

/**
 * Schema for PixelArt API error responses.
 */
const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      type: z.string().nullish(),
      code: z.string().nullish(),
    })
    .nullish(),
});

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The size of the generated image (e.g. "256x256", "512x512", "1024x1024").
       */
      size: z.string().nullish(),

      /**
       * The artistic style to apply to the generated image.
       * - `pixel`: Classic pixel art style.
       * - `retro`: Retro-inspired pixel art with a vintage look.
       * - `8bit`: 8-bit video game aesthetic.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density of the generated image.
       * Higher values produce more detailed pixel art.
       */
      pixelDensity: z.number().min(1).max(8).nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

